import java.util.ArrayList;
import java.util.List;
public class Main {
    public static void main(String[] args) {
        Pizza p = new PizzaBuilder().size(Size.MEDIUM).crust(Crust.REGULAR).addTopping(Topping.MOZZARELLA).build();
        double base = p.getBasePrice();
        List<PizzaDecorator> ex = new ArrayList<>(); ex.add(new ExtraCheese());
        double withExtra = base + ex.stream().mapToDouble(PizzaDecorator::getCost).sum();
        System.out.println("OK_2 BASE=" + String.format("%.2f", base) + " WITH=" + String.format("%.2f", withExtra) + " DIFF=" + String.format("%.2f", withExtra - base));
    }
}

